SELECT Id, FirstName, LastName, Email, AccountId
FROM Contact
WHERE replace(Id,'#','') IN (
  SELECT replace(ConvertedContactId,'#','') FROM sales_pipeline.Lead WHERE replace(Id,'#','')='00QWt0000089AekMAE'
)
LIMIT 1;

